# Initializes an MSVC build environment for the current PowerShell session.
# Generated by: adm --init-msvc
# Uses Launch-VsDevShell.ps1 (Visual Studio 2022+)

# IMPORTANT: dot-source this script to keep env in the current session:
#   . .\tools\init_msvc.ps1

$ErrorActionPreference = 'Stop'
if ((Get-Command cl -ErrorAction SilentlyContinue) -and (Get-Command msbuild -ErrorAction SilentlyContinue)) {
  Write-Host "[OK] MSVC environment already initialized."
  return
}

$launchScript = "C:\Program Files\Microsoft Visual Studio\18\Community\Common7\Tools\Launch-VsDevShell.ps1"
if (-not (Test-Path -LiteralPath $launchScript)) {
  Write-Error "Launch-VsDevShell.ps1 not found: $launchScript"
}

# Launch-VsDevShell.ps1 modifies environment of the current PowerShell session
# when dot-sourced. We'll invoke it with appropriate parameters.
& $launchScript -Latest -SkipAutomaticLocation -Arch amd64 -HostArch amd64

# Verify tools are available
if (-not (Get-Command cl -ErrorAction SilentlyContinue)) {
  Write-Error "cl.exe not found after Launch-VsDevShell.ps1"
}
if (-not (Get-Command msbuild -ErrorAction SilentlyContinue)) {
  Write-Error "msbuild.exe not found after Launch-VsDevShell.ps1"
}

Write-Host "[OK] MSVC environment initialized."
Write-Host ("cl=" + [bool](Get-Command cl -ErrorAction SilentlyContinue))
Write-Host ("msbuild=" + [bool](Get-Command msbuild -ErrorAction SilentlyContinue))
